function [e2,x2,y2,z2] = fPad3DEfld(e1,x1,y1,z1,dim2,varargin)%% function pad 3d e-field for FFT%% [e2,x2,y2,z2] = fPad3DEfld(e1,x1,y1,z1,dim2,varargin)%% e2: 3d array of e-filed (y,x,z)% x2: new x % y2: new y % z2: new z%% e1: 3d array of e-filed (y,x,z)% x1: x % y1: y % z1: z% dim2: desired dimension [y,x,z]% offset: [y,x,z]%% Written by Kei Nakamura%% 2018/11/30: created%%% main body% off setif nargin==5    os = [0 0 0];else    os = varargin{1};end% y-dimsz1 = size(e1); % size 1dy = dim2(1) - sz1(1);      % total pad in yif dy~=0    % field    dy1 = floor(0.5*dy) + mod(dy,2) + os(1);    % pad in y pre    dy2 = floor(0.5*dy) - os(1);                % pad in y pre    pad1 = zeros(dy1,sz1(2),sz1(3));    pad2 = zeros(dy2,sz1(2),sz1(3));    e2 = cat(1,pad1,e1,pad2);    % axis    dya = y1(2)-y1(1);  % dy    pad1 = [y1(1)-dya*dy1:dya:y1(1)-dya];   % pad for axis    pad2 = [y1(end)+dya:dya:y1(end)+dy2*dya];     y2 = [pad1';y1;pad2'];else    e2 = e1; y2 = y1;end% x-dimdx = dim2(2) - sz1(2);if dx~=0    dx1 = floor(0.5*dx) + mod(dx,2) + os(2);    % pad in y pre    dx2 = floor(0.5*dx) - os(2);                % pad in y pre    pad1 = zeros(dim2(1),dx1,sz1(3));    pad2 = zeros(dim2(1),dx2,sz1(3));    e2 = cat(2,pad1,e2,pad2);    % axis    dxa = x1(2)-x1(1);  % dx    pad1 = [x1(1)-dxa*dx1:dxa:x1(1)-dxa];   % pad for axis    pad2 = [x1(end)+dxa:dxa:x1(end)+dx2*dxa];     x2 = [pad1';x1;pad2'];else    x2 = x1;end% z-dimdz = dim2(3) - sz1(3);if dz~=0    dz1 = floor(0.5*dz) + mod(dz,2) + os(3);    % pad in y pre    dz2 = floor(0.5*dz) - os(3);                % pad in y pre    pad1 = zeros(dim2(1),dim2(2),dz1);    pad2 = zeros(dim2(1),dim2(2),dz2);    e2 = cat(3,pad1,e2,pad2);    % axis    dza = z1(2)-z1(1);  % dx    pad1 = [z1(1)-dza*dz1:dza:z1(1)-dza];   % pad for axis    pad2 = [z1(end)+dza:dza:z1(end)+dz2*dza];     z2 = [pad1';z1;pad2'];else    z2 = z1;end
